"""
Quality Integration Module
Provides the integration point between the Master Quality System and OpenCode's interactive.py
This module handles the transition from existing systems to enhanced quality recovery
"""

import asyncio
import time
from typing import Dict, List, Optional, Tuple, Any
from rich.console import Console

console = Console()

try:
    from .master_quality_system import MasterQualitySystem, SystemMode
except ImportError:
    from master_quality_system import MasterQualitySystem, SystemMode

class QualityIntegrationManager:
    """Manager for integrating quality system with existing OpenCode"""

    def __init__(self, interactive_instance):
        self.interactive = interactive_instance
        self.config = interactive_instance.config

        # Initialize master quality system
        self.quality_system = MasterQualitySystem({
            'enable_quality_recovery': True,
            'enable_instant_hooks': True,
            'enable_rag_feedback': True,
            'enable_observer_pattern': True
        })

        # Integration state
        self.quality_enabled = True
        self.fallback_count = 0
        self.integration_metrics = {
            'total_requests': 0,
            'quality_system_used': 0,
            'fallback_used': 0,
            'average_improvement': 0.0
        }

    async def enhanced_generate(self, prompt: str, system_prompt: str = None, **kwargs) -> str:
        """Enhanced generation that uses quality system with fallback to original"""

        if hasattr(self.interactive, 'history') and hasattr(self.interactive.history, 'debug_timing') and self.interactive.history.debug_timing:
            console.print(f"[dim]DEBUG: enhanced_generate called with system_prompt={system_prompt is not None}, task_type={kwargs.get('task_type', 'NOT_IN_KWARGS')}[/dim]")
        self.integration_metrics['total_requests'] += 1

        # Skip quality system for tool_use to preserve task_type correctly
        if kwargs.get('task_type') == 'tool_use':
            if hasattr(self.interactive, 'history') and hasattr(self.interactive.history, 'debug_timing') and self.interactive.history.debug_timing:
                console.print(f"[dim]DEBUG: Bypassing quality system for tool_use task[/dim]")
            return await self._fallback_generate(prompt, system_prompt, **kwargs)

        if not self.quality_enabled:
            # Quality system disabled - use original method
            if hasattr(self.interactive, 'history') and hasattr(self.interactive.history, 'debug_timing') and self.interactive.history.debug_timing:
                console.print(f"[dim]DEBUG: Quality system disabled, using fallback[/dim]")
            return await self._fallback_generate(prompt, system_prompt, **kwargs)

        try:
                    # Check if native tool calling is active
            # Check if native tool calling is active
            tools_active = hasattr(self.interactive, '_current_tool_schemas') and self.interactive._current_tool_schemas

            # CRITICAL FIX: Quality system doesn't support system_prompt parameter
            # Fall back to original method to preserve system_prompt for tool calling
            if system_prompt:
                console.print(f"[dim yellow]Quality system bypassed to preserve system_prompt for tools[/dim yellow]")
                return await self._fallback_generate(prompt, system_prompt, **kwargs)

            # Prepare context for quality system
            context = self._prepare_quality_context(**kwargs)

            # Use master quality system
            response, metadata = await self.quality_system.process_user_input(
                prompt, self.interactive, context
            )

            self.integration_metrics['quality_system_used'] += 1

            # Log performance metrics
            self._log_performance_metrics(prompt, response, metadata)

            return response

        except Exception as e:
            # Fallback to original system
            print(f"Quality system fallback: {str(e)[:100]}")
            self.fallback_count += 1
            self.integration_metrics['fallback_used'] += 1

            # Disable quality system temporarily if too many failures
            if self.fallback_count > 5:
                print("Temporarily disabling quality system due to failures")
                self.quality_enabled = False

            return await self._fallback_generate(prompt, system_prompt, **kwargs)

    def _prepare_quality_context(self, **kwargs) -> Dict[str, Any]:
        """Prepare context information for quality system"""

        context = {}

        # Detect if RAG should be active based on task type
        task_type = kwargs.get('task_type', 'standard')
        context['task_type'] = task_type  # Pass task_type to quality system
        context['rag_active'] = task_type in ['research', 'analysis', 'complex']

        # Detect tools being used
        context['tools_used'] = kwargs.get('tools_used', [])

        # Add mode information
        current_mode = getattr(self.interactive, '_current_mode', 'auto')
        context['opencode_mode'] = current_mode

        # Add resource information
        context['resources_percentage'] = self.config.runtime.resources

        return context

    async def _fallback_generate(self, prompt: str, system_prompt: str = None, **kwargs) -> str:
        """Fallback to original generation method"""

        if hasattr(self.interactive, 'history') and hasattr(self.interactive.history, 'debug_timing') and self.interactive.history.debug_timing:
            console.print(f"[dim]DEBUG: Fallback called with task_type={kwargs.get('task_type', 'NOT_FOUND')}[/dim]")
        try:
            # Use original _generate_with_resources to avoid recursion
            if hasattr(self.interactive, '_original_generate_with_resources'):
                # Propagate overrides (policy caps/options) when available
                return await self.interactive._original_generate_with_resources(
                    prompt,
                    system_prompt,
                    kwargs.get('task_type', 'standard'),
                    overrides=kwargs.get('overrides')
                )
            else:
                # Direct ollama call as ultimate fallback
                return await self.interactive.ollama_client.generate(
                    prompt, system_prompt, kwargs.get('task_type', 'standard')
                )
        except Exception as e:
            print(f"Fallback generation error: {str(e)}")
            # Ultimate fallback - return basic error message
            return f"Error: Unable to generate response"

    def _log_performance_metrics(self, prompt: str, response: str, metadata: Dict[str, Any]):
        """Log performance metrics for analysis"""

        # Calculate response quality indicators
        response_length = len(response)
        processing_time = metadata.get('processing_time', 0)
        tier_used = metadata.get('tier', 'unknown')

        # Simple quality heuristics
        quality_indicators = {
            'response_length_appropriate': 50 <= response_length <= 1000,
            'fast_response': processing_time < 1.0,
            'instant_tier_used': tier_used == 'instant',
            'hook_utilized': 'hook_used' in metadata
        }

        quality_score = sum(quality_indicators.values()) / len(quality_indicators)

        # Update running average
        current_avg = self.integration_metrics['average_improvement']
        total_quality_requests = self.integration_metrics['quality_system_used']

        if total_quality_requests > 1:
            self.integration_metrics['average_improvement'] = (
                (current_avg * (total_quality_requests - 1) + quality_score) / total_quality_requests
            )
        else:
            self.integration_metrics['average_improvement'] = quality_score

    def get_quality_status(self) -> Dict[str, Any]:
        """Get comprehensive quality integration status"""

        system_status = self.quality_system.get_system_status()

        integration_status = {
            'quality_enabled': self.quality_enabled,
            'integration_metrics': self.integration_metrics,
            'fallback_count': self.fallback_count,
            'system_health': 'healthy' if self.fallback_count < 3 else 'degraded',
            'quality_system_status': system_status
        }

        return integration_status

    def optimize_quality_system(self) -> Dict[str, Any]:
        """Optimize the quality system based on usage patterns"""

        optimization_result = self.quality_system.optimize_system()

        # Add integration-specific optimizations
        if self.integration_metrics['total_requests'] > 100:
            usage_rate = self.integration_metrics['quality_system_used'] / self.integration_metrics['total_requests']

            if usage_rate < 0.5:
                optimization_result['optimizations_applied'].append(
                    "Increased quality system engagement threshold"
                )

        return optimization_result

    def set_quality_mode(self, mode: str):
        """Set quality system mode"""

        mode_mapping = {
            'fast': SystemMode.PERFORMANCE_FIRST,
            'auto': SystemMode.BALANCED,
            'think': SystemMode.FEATURE_RICH,
            'learning': SystemMode.LEARNING
        }

        if mode in mode_mapping:
            self.quality_system.set_mode(mode_mapping[mode].value)
        else:
            raise ValueError(f"Invalid quality mode: {mode}")

    def enable_quality_system(self):
        """Enable quality system"""
        self.quality_enabled = True
        self.fallback_count = 0

    def disable_quality_system(self):
        """Disable quality system (fallback to original)"""
        self.quality_enabled = False

    def reset_metrics(self):
        """Reset integration metrics"""
        self.integration_metrics = {
            'total_requests': 0,
            'quality_system_used': 0,
            'fallback_used': 0,
            'average_improvement': 0.0
        }
        self.fallback_count = 0


def integrate_quality_system(interactive_instance) -> QualityIntegrationManager:
    """
    Integrate quality system with an existing OpenCode interactive instance

    Usage:
        quality_manager = integrate_quality_system(interactive_instance)

        # Replace the original generate method
        original_generate = interactive_instance.some_generate_method
        interactive_instance.some_generate_method = quality_manager.enhanced_generate
    """

    return QualityIntegrationManager(interactive_instance)


# Example integration code for interactive.py
def add_quality_enhancement_to_interactive():
    """
    Example of how to integrate quality system into interactive.py
    This would be added to the InteractiveMode class
    """

    integration_code = '''
    # Add to InteractiveMode.__init__():
    from .quality_integration import integrate_quality_system

    # Initialize quality integration
    self.quality_manager = integrate_quality_system(self)

    # Override generation method
    self.original_generate_with_resources = self._generate_with_resources
    self._generate_with_resources = self.quality_manager.enhanced_generate

    # Add quality commands
    def handle_quality_command(self, command: str):
        """Handle quality system commands"""
        if command.startswith('/quality status'):
            status = self.quality_manager.get_quality_status()
            console.print(f"Quality System Status: {status['system_health']}")
            console.print(f"Quality Usage Rate: {status['integration_metrics']['quality_system_used'] / max(1, status['integration_metrics']['total_requests']) * 100:.1f}%")

        elif command.startswith('/quality optimize'):
            result = self.quality_manager.optimize_quality_system()
            console.print(f"Optimizations applied: {len(result['optimizations_applied'])}")
            for opt in result['optimizations_applied']:
                console.print(f"  • {opt}")

        elif command.startswith('/quality mode'):
            mode = command.split()[-1]
            try:
                self.quality_manager.set_quality_mode(mode)
                console.print(f"Quality mode set to: {mode}")
            except ValueError as e:
                console.print(f"Error: {e}")

        elif command == '/quality enable':
            self.quality_manager.enable_quality_system()
            console.print("Quality system enabled")

        elif command == '/quality disable':
            self.quality_manager.disable_quality_system()
            console.print("Quality system disabled - using original processing")
    '''

    return integration_code


if __name__ == "__main__":
    print("Quality Integration Module")
    print("This module provides integration between Master Quality System and OpenCode")
    print("\nIntegration example:")
    print(add_quality_enhancement_to_interactive())
